import subprocess, json, time

ALPACA_CMD = '~/bin/alpaca'

def _run(args, retries=1, delay=3, ignore_404=False):
    cmd = [os.path.expanduser(ALPACA_CMD)] + args
    env = os.environ.copy()
    env['ALPACA_API_KEY'] = os.environ['ALPACA_API_KEY']
    env['ALPACA_SECRET_KEY'] = os.environ['ALPACA_SECRET_KEY']
    env['PATH'] = os.environ.get('PATH', '') + ':' + os.path.expanduser('~/bin')
    for attempt in range(retries + 1):
        try:
            r = subprocess.run(cmd, capture_output=True, text=True, env=env, timeout=30)
            if r.returncode == 0:
                out = r.stdout.strip()
                if not out:
                    return {}
                try:
                    return json.loads(out)
                except:
                    return out
            err = r.stderr.strip()
            if ignore_404 and r.returncode == 1 and 'position does not exist' in err:
                return None
            if attempt < retries and ('rate limit' in err.lower() or r.returncode == 429):
                time.sleep(delay)
                continue
            if not ignore_404:
                print(f'CLI error ({r.returncode}): {err[:200]}')
            return None
        except Exception as e:
            print(f'CLI exception: {e}')
            return None
    return None

